import clsx from 'clsx';
import * as React from 'react';
import { useCssScope } from '../../../config-provider/hooks';
import type { VirtualScrollAreaProps } from './interface';
import SimpleBar from 'simplebar-react';
import './simplebar-scrollarea.less';

export const SimpleBarScrollArea_unstable = React.forwardRef<HTMLDivElement, Omit<VirtualScrollAreaProps, 'virtual'>>(
  ({ className, showScrollBars = 'whenScrolling', ...restProps }, ref) => {
    const cssScope = useCssScope('scrollArea-simplebar');

    return (
      <SimpleBar
        scrollableNodeProps={{ ref }}
        autoHide={showScrollBars !== 'always'}
        className={clsx(className, cssScope())}
        {...restProps}
      />
    );
  },
);
